function MapWidget({ containerId }) {
  useEffect(() => {
    // Map library requires one-time imperative initialization against a DOM node.
    // There is no reactive equivalent; the library manages its own update cycle.
    const map = L.map(containerId).setView([51.505, -0.09], 13);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png').addTo(map);
    return () => map.remove();
  }, [containerId]);

  return <div id={containerId} style={{ height: 400 }} />;
}
